"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["693744"],{849728(e){e.exports=JSON.parse('{"tag":{"label":"variables","permalink":"/sdk/tags/variables","allTagsPath":"/sdk/tags","count":2,"items":[{"id":"guides/form-formatters-guide","title":"Form Formatters","description":"Guide for adding formatters to ServiceNow forms using the Form API. Formatters display special UI components (activity streams, process flows, knowledge panels, checklist, parent breadcrumb) that are not regular table fields.","permalink":"/sdk/guides/form-formatters-guide"},{"id":"guides/service-catalog-guide","title":"Service Catalog","description":"Guide for building ServiceNow Service Catalog components using the Fluent API \u2014 catalog items [sccatitem], record producers [sccatitemproducer], variables [itemoptionnew], variable sets [itemoptionnewset], UI policies [cataloguipolicy], and client scripts [catalogscriptclient]. Whenever the requirement is a form that captures user input and creates a record in a table \u2014 e.g., problem, incident, change_request, or a custom table, including mapping mandatory fields, applying validation, and confirming submission \u2014 the correct metadata is a Record Producer (CatalogItemRecordProducer), NOT a UI Page or a Scripted REST API. A Record Producer provides the form, field mapping (mapToField), validation (catalog UI policies + client scripts), and built-in submit/confirm behavior with no custom page or endpoint. Use a catalog item instead when ordering goods/services with approvals and fulfillment. Also use this guide when the user mentions service catalog, catalog items, record producers, variables, variable sets, UI policies, client scripts, form validation, dynamic fields, onChange, onLoad, onSubmit, ordering, or self-service. Includes property references, code examples, field mapping, scripting patterns, and best practices for end-to-end Service Catalog configuration. Only supported in SDK 4.3.0 or higher","permalink":"/sdk/guides/service-catalog-guide"}],"unlisted":false}}')}}]);